#include <bits/stdc++.h>
using namespace std;
int n,v[400005];
long long ans;
priority_queue<int,vector<int>,greater<int> > lm,rm;
int main(){
	scanf("%d",&n);
	for(int i=1;i<=2*n;i++){
		scanf("%d",&v[i]);
		ans+=v[i];
	}
	for(int i=n,j=n+1;i>0;i--,j++){
		lm.push(v[i]),rm.push(v[j]);
		if(lm.top()<rm.top())
			ans-=lm.top(),lm.pop();
		else
			ans-=rm.top(),rm.pop();
	}
	printf("%lld",ans);
	return 0;
}
